### Start Live Replication for RxDB Collection

Source: https://github.com/pubkey/rxdb/blob/master/docs-src/docs/articles/local-first-future.md

Initiates a continuous, live replication for a specified RxDB collection. It configures both push and pull handlers for synchronizing data with a server. The replication uses a stream for real-time updates and supports conflict resolution.

```typescript
const replicationState = await replicateRxCollection({
  collection: db.todos,
  replicationIdentifier: 'my-todos-replication',
  live: true,
  push: {
    async handler(changedDocs) {
      const response = await fetch('/api/todos/push', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(changedDocs)
      });
      const { errorDocuments } = await response.json();
      return errorDocuments; 
    }
  },
  pull: {
    async handler(lastCheckpoint, batchSize) {
      const url = '/api/todos/pull?checkpoint=' + 
        encodeURIComponent(JSON.stringify(lastCheckpoint)) + 
        '&limit=' + batchSize;
      const response = await fetch(url);
      const { documents, checkpoint } = await response.json();
      return {
        documents,
        checkpoint
      };
    },
    stream$: async function () {
      const eventSource = new EventSource('/api/todos/pull-stream');
      return new Observable(subscriber => {
        eventSource.onmessage = (msg) => {
          const data = JSON.parse(msg.data);
          subscriber.next({
            documents: data.documents,
            checkpoint: data.checkpoint
          });
        };
        return () => eventSource.close();
      });
    }
  },
});
```

