### Initialize RxDB with Types and ORM Methods (TypeScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs/tutorials/typescript.html

Demonstrates initializing an RxDB database with custom types and ORM methods. It includes defining the schema, document methods, collection static methods, and then using them during collection creation and subsequent database operations.

```typescript
const myDatabase: MyDatabase = await createRxDatabase<MyDatabaseCollections>({
    name: 'mydb',
    storage: getRxStorageLocalstorage()
});

const heroSchema: RxJsonSchema<HeroDocType> = {
    title: 'human schema',
    description: 'describes a human being',
    version: 0,
    keyCompression: true,
    primaryKey: 'passportId',
    type: 'object',
    properties: {
        passportId: {
            type: 'string'
        },
        firstName: {
            type: 'string'
        },
        lastName: {
            type: 'string'
        },
        age: {
            type: 'integer'
        }
    },
    required: ['passportId', 'firstName', 'lastName']
};

const heroDocMethods: HeroDocMethods = {
    scream: function(this: HeroDocument, what: string) {
        return this.firstName + ' screams: ' + what.toUpperCase();
    }
};

const heroCollectionMethods: HeroCollectionMethods = {
    countAllDocuments: async function(this: HeroCollection) {
        const allDocs = await this.find().exec();
        return allDocs.length;
    }
};

await myDatabase.addCollections({
    heroes: {
        schema: heroSchema,
        methods: heroDocMethods,
        statics: heroCollectionMethods
    }
});

myDatabase.heroes.postInsert(
    function myPostInsertHook(
        this: HeroCollection,
        docData: HeroDocType,
        doc: HeroDocument
    ) {
        console.log('insert to ' + this.name + '-collection: ' + doc.firstName);
    },
    false
);

const hero: HeroDocument = await myDatabase.heroes.insert({
    passportId: 'myId',
    firstName: 'piotr',
    lastName: 'potter',
    age: 5
});

console.log(hero.firstName);
const amount: number = await myDatabase.heroes.countAllDocuments();
console.log(amount);

myDatabase.close();
```

